@router.post("/", response_model=NoteOut, status_code=201)
def create_note(data: NoteCreate, db: Session = Depends(get_db)):
    return note_service.create(db, title=data.title, content=data.content)

@router.get("/", response_model=list[NoteOut])
def list_notes(db: Session = Depends(get_db)):
    return note_service.get_all(db)


@router.get("/{note_id}", response_model=NoteOut)
def get_note(note_id: int, db: Session = Depends(get_db)):
    note = note_service.get_by_id(db, note_id)
    if not note:
        raise HTTPException(status_code=404, detail="Note not found")
    return note

@router.put("/{note_id}", response_model=NoteOut)
def update_note(note_id: int, data: NoteUpdate, db: Session = Depends(get_db)):
    updates = data.model_dump(exclude_unset=True)
    note = note_service.update(db, note_id, **updates)
    if not note:
        raise HTTPException(status_code=404, detail="Note not found")
    return note

@router.delete("/{note_id}")
def delete_note(note_id: int, db: Session = Depends(get_db)):
    if not note_service.delete(db, note_id):
        raise HTTPException(status_code=404, detail="Note not found")
    return {"ok": True}

def update(db: Session, note_id: int, **kwargs) -> Note | None:
    note = get_by_id(db, note_id)
    if not note:
        return None
    for key, value in kwargs.items():
        if hasattr(note, key):
            setattr(note, key, value)
    if "title" in kwargs and kwargs["title"] is not None:
        update_entity_tag(db, "note", note_id, kwargs["title"])
    db.commit()
    db.refresh(note)
    return note

export async function getNotes(): Promise<Note[]> {
	const res = await fetch(`${BASE}/`);
	return res.json();
}

export async function createNote(data: { title: string; content?: string }): Promise<Note> {
	const res = await fetch(`${BASE}/`, {
		method: 'POST',
		headers: { 'Content-Type': 'application/json' },
		body: JSON.stringify(data)
	});
	return res.json();
}

export async function updateNote(id: number, data: Partial<Note>): Promise<Note> {
	const res = await fetch(`${BASE}/${id}`, {
		method: 'PUT',
		headers: { 'Content-Type': 'application/json' },
		body: JSON.stringify(data)
	});
	return res.json();
}

export async function deleteNote(id: number): Promise<void> {
	await fetch(`${BASE}/${id}`, { method: 'DELETE' });
}

